"use strict";parserFactory.register("neobook.org",()=>new NeobookParser);class NeobookParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=t.querySelector("div#book-about-chapters");return util.hyperlinksToChapterList(e)}findContent(t){return Parser.findConstrutedContent(t)}extractTitleImpl(t){return t.querySelector("div.book-title")}findCoverImageUrl(t){return util.getFirstImgSrc(t,"div.book-cover-wrapper")}async fetchChapter(t){let e=(await HttpClient.fetchHtml(t)).responseXML,r=this.extractJson(e);return this.buildChapter(r,t)}extractJson(t){let e="var data = ",r=[...t.querySelectorAll("script")].filter(t=>t.textContent.includes(e)).map(t=>t.textContent)[0];return util.locateAndExtractJson(r,e)}buildChapter(t,e){let r=t.chapters.filter(t=>null!=t?.data?.html)[0],o=Parser.makeEmptyDocForContent(e),n=o.dom.createElement("h1");n.textContent=r.data.title,o.content.appendChild(n);let a=util.sanitize(r.data.html);return util.moveChildElements(a.body,o.content),o.dom}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll("#book-about-description")]}}